-- ─────────────────────────────────────────────────────────
-- Migration 11: Seed help articles
-- ─────────────────────────────────────────────────────────

-- Clear existing articles before re-seeding (safe since admin-only insert)
delete from help_articles where slug like 'lumenfi-%';

insert into help_articles (slug, title, category, body, locale, sort_order) values
-- Getting Started
('lumenfi-welcome', 'ยินดีต้อนรับสู่ Lumenfi', 'getting-started', E'# ยินดีต้อนรับ\n\nLumenfi เป็นแอปการเงินส่วนตัวที่ช่วยให้คุณเข้าใจการเงินของตัวเอง วางแผนปลดหนี้ ออมเงิน และวิเคราะห์สถานะประกัน\n\n## เริ่มต้นใช้งาน 3 ขั้นตอน\n\n1. **เพิ่มบัญชีแรกของคุณ** — ที่ /accounts/new\n2. **บันทึกรายรับ-รายจ่าย** — ปุ่ม + เพิ่มรายการ\n3. **ดูสถานะ** — Dashboard จะคำนวณสุขภาพการเงินให้\n\nหลังจากใช้สัก 1 เดือน ระบบจะมีข้อมูลพอที่จะวิเคราะห์และให้คำแนะนำได้แม่นยำขึ้น', 'th', 1),

('lumenfi-add-account', 'วิธีเพิ่มบัญชี', 'getting-started', E'# เพิ่มบัญชีใหม่\n\n1. ไปที่ **บัญชีของฉัน** (เมนูซ้ายหรือ /accounts)\n2. กด **+ เพิ่มบัญชี**\n3. เลือกประเภท: เงินสด, ธนาคาร, บัตรเครดิต, e-Wallet, ออมทรัพย์\n4. กรอกชื่อ + ยอดเริ่มต้น\n5. (ไม่บังคับ) ใส่เลขบัญชี — ใช้กับ OCR สแกนสลิปได้\n\n## บัตรเครดิต\nกรอก **วงเงินสูงสุด** ด้วย ระบบจะคำนวณ utilization ให้\n\n## ทำไมต้องเพิ่มบัญชี?\nแอพต้องรู้ว่าเงินอยู่ที่ไหน ถึงจะคำนวณ Net Worth + Cash Flow ได้ครบ', 'th', 2),

('lumenfi-add-transaction', 'บันทึกรายรับ-รายจ่าย', 'transactions', E'# วิธีบันทึกรายการ\n\n1. กด **+ เพิ่มรายการ** (ปุ่มกลางล่างบนมือถือ หรือ sidebar บน desktop)\n2. เลือก: รายจ่าย / รายรับ / โอน\n3. กรอกจำนวน + เลือกหมวดหมู่ + บัญชี + วันที่\n4. กดบันทึก\n\n## OCR สแกนใบเสร็จ\nกดปุ่ม **อัปโหลดรูป** หรือ **ถ่ายรูป** AI จะอ่านยอด หมวด และวันที่จากใบเสร็จให้\n\n## ผูกกับเป้าหมาย\nถ้ามีเป้าหมายเก็บเงิน เลือก "ผูกกับเป้าหมาย" — ระบบจะอัปเดตยอดเป้าหมายอัตโนมัติ\n\n## บันทึกเป็นรายการประจำ\nเปิดสวิตช์ "บันทึกเป็นรายการประจำ" ระบบจะสร้างรายการนี้อัตโนมัติทุกเดือน', 'th', 3),

('lumenfi-debts', 'จัดการหนี้สินและวางแผนปลดหนี้', 'debts', E'# จัดการหนี้สิน\n\n1. เพิ่มหนี้ที่ /debts/new\n2. ระบุ: ชื่อ, ประเภท, ยอดต้น, ดอก%/ปี, ค่างวด/เดือน\n3. ระบบจะคำนวณ DTI ratio ให้อัตโนมัติ\n\n## วางแผนปลดหนี้\n- ไปที่ **วางแผนชำระหนี้** (/tools/debt)\n- ระบบจะดึงหนี้ทั้งหมดมาคำนวณ\n- กลยุทธ์ที่เลือกได้:\n  - **Avalanche** — ดอกสูงก่อน (ประหยัดดอกที่สุด)\n  - **Snowball** — ก้อนเล็กก่อน (สร้างกำลังใจเร็ว)\n- ใส่ "จ่ายเพิ่มต่อเดือน" → ระบบคำนวณวันหมดหนี้\n\n## AI Advisor\nกดปุ่ม **ขอคำแนะนำจาก AI** AI จะวิเคราะห์ข้อมูลคุณและให้คำแนะนำเฉพาะ', 'th', 4),

('lumenfi-budgets', 'ตั้งงบประมาณรายเดือน', 'budgets', E'# งบประมาณรายเดือน\n\n1. ไปที่ **งบประมาณ** (/budgets)\n2. กดดินสอข้างหมวดที่ต้องการตั้งงบ\n3. ใส่จำนวนเงิน → บันทึก\n\nระบบจะ track ยอดใช้จ่ายของคุณในเดือนนั้น และเตือนเมื่อใกล้เกินงบ\n\n## เคล็ดลับ\n- ใช้สูตร 50/30/20: 50% ใช้จำเป็น, 30% ใช้เพื่อความสุข, 20% ออม/ลงทุน\n- ดูยอดเฉลี่ย 3 เดือนล่าสุดก่อนตั้งงบ ให้สมเหตุสมผล', 'th', 5),

('lumenfi-goals', 'ตั้งเป้าหมายการเงิน', 'goals', E'# เป้าหมายการเงิน\n\n1. ไปที่ **เป้าหมาย** (/goals)\n2. กดเพิ่มเป้าหมาย\n3. ตั้งชื่อ + ยอดเป้าหมาย + วันที่ตั้งใจถึง\n\n## ผูกกับบัญชี\nถ้าผูกกับบัญชีออมทรัพย์ ระบบจะนับยอดเงินในบัญชีเป็นความคืบหน้า\n\n## เก็บเงินสู่เป้าหมาย\n- ตอนเพิ่มรายการ เลือก **ผูกกับเป้าหมาย** ระบบจะเพิ่มยอดอัตโนมัติ\n- หรือกดปุ่ม **เติมเงิน** ที่หน้าเป้าหมาย\n\n## เป้าหมายแนะนำ\n- เงินสำรองฉุกเฉิน 6 เท่าของรายจ่าย\n- ดาวน์บ้าน\n- เกษียณ', 'th', 6),

('lumenfi-ai', 'ใช้งาน AI Advisor', 'ai', E'# AI Advisor\n\nLumenfi ใช้ระบบ Bring Your Own Key (BYOK) — คุณใช้ API key ของคุณเอง ข้อมูลไม่ผ่านเซิร์ฟเวอร์เรา\n\n## ตั้งค่าครั้งแรก\n1. ไปที่ **AI Settings** (/ai/settings)\n2. เลือก provider: Anthropic, OpenAI, Gemini, OpenRouter\n3. ใส่ API key (เข้ารหัสเก็บใน DB)\n4. กด **ทดสอบการเชื่อมต่อ**\n\n## API Key หาที่ไหน\n- **Anthropic**: console.anthropic.com\n- **OpenAI**: platform.openai.com\n- **Gemini**: aistudio.google.com\n- **OpenRouter**: openrouter.ai\n\n## ค่าใช้จ่าย\n~$0.01-0.05 ต่อคำถามเฉพาะ ขึ้นกับ provider', 'th', 7),

('lumenfi-insurance', 'วิเคราะห์ประกัน', 'insurance', E'# วิเคราะห์ประกัน\n\n1. ไปที่ **ประกัน** (/insurance)\n2. ระบบจะวิเคราะห์ความคุ้มครองที่ "ขาด" จากข้อมูลในแอพ:\n   - ประกันชีวิต (ตามจำนวน dependents + หนี้)\n   - ประกันสุขภาพ (ตามอายุ)\n   - ประกันโรคร้ายแรง (CI)\n   - ประกันอุบัติเหตุ\n   - เงินสำรองฉุกเฉิน\n\n## ขอใบเสนอ\nกด "ขอใบเสนอประกัน" — ตัวแทน Lumenfi (BLA + Allianz) ติดต่อกลับใน 1 วัน\n\n## บันทึกกรมธรรม์ที่มีอยู่\nที่ /insurance/policies เพิ่มกรมธรรม์ที่ทำไว้แล้ว ระบบจะ:\n- คำนวณช่องว่างให้แม่นขึ้น\n- เตือนวันต่ออายุ', 'th', 8),

('lumenfi-tax', 'คำนวณภาษีบุคคลธรรมดา', 'tools', E'# คำนวณภาษี\n\nไปที่ **คำนวณภาษี** (/tools/tax)\n\n1. ใส่รายได้ทั้งปี\n2. ระบุค่าลดหย่อน: ส่วนตัว, คู่สมรส, ประกันชีวิต, RMF/SSF, บริจาค ฯลฯ\n3. ระบบคำนวณภาษีที่ต้องจ่าย + แสดงคำแนะนำลดหย่อน\n\n## เคล็ดลับลดหย่อน\n- ประกันชีวิต/บำนาญ: หักได้สูงสุด 100,000\n- ประกันสุขภาพ: 25,000\n- RMF: 30% ของรายได้ ไม่เกิน 500,000\n- SSF: 30% ของรายได้ ไม่เกิน 200,000', 'th', 9),

('lumenfi-export', 'ส่งออกข้อมูล / ลบบัญชี', 'privacy', E'# ความเป็นส่วนตัว (PDPA)\n\nไปที่ **ความเป็นส่วนตัว** (/settings/privacy)\n\n## ส่งออกข้อมูล\nกดปุ่ม **ดาวน์โหลด JSON** จะได้ไฟล์ลำดับเวลาทั้งหมด — รายการ บัญชี เป้าหมาย หนี้ ทุกอย่าง\n\n## ลบบัญชี\n1. กด **ลบบัญชีของฉัน**\n2. พิมพ์อีเมลยืนยัน\n3. ข้อมูลทั้งหมดถูกลบถาวร — ไม่สามารถกู้คืน\n\nตามกฎหมาย PDPA ของไทย คุณมีสิทธิ์ทั้งสองอย่างนี้', 'th', 10),

('lumenfi-faq-data', 'ข้อมูลเก็บไว้ที่ไหน ปลอดภัยไหม', 'privacy', E'# ความปลอดภัยข้อมูล\n\n## เก็บที่ไหน\nข้อมูลเก็บใน **Supabase** (PostgreSQL) hosting ที่ Singapore (ap-southeast-1)\n\n## RLS (Row Level Security)\nข้อมูลของคุณ user อื่นเห็นไม่ได้ — แม้แอพมี bug\n\n## รหัสผ่าน\nเก็บแบบ hash (bcrypt) — เราเองก็มองไม่เห็น\n\n## API Key ของ AI\nเข้ารหัสด้วย AES-GCM ก่อนเก็บ — เราเองก็ถอดรหัสไม่ได้ (key อยู่ใน server env เท่านั้น)\n\n## ไม่มีการขายข้อมูล\nเราไม่ขายข้อมูลให้ใคร', 'th', 11),

('lumenfi-faq-cost', 'ใช้ฟรีจริงๆ หรือ?', 'general', E'# ค่าใช้จ่าย\n\n## ตอนนี้\n**ฟรีทั้งหมด** — ทุกฟีเจอร์ใช้ได้ไม่มีค่าใช้จ่าย\n\n## อนาคต\nอาจจะเป็น Freemium\n- Free: ฟีเจอร์ส่วนใหญ่\n- Pro: ฟีเจอร์ขั้นสูง (AI advanced, รายงาน PDF, family sharing)\n\n## API Cost (ของคุณ)\nถ้าใช้ AI Advisor / OCR — เราใช้ API key ของคุณเอง — ค่าใช้จ่าย ~$0.01-0.05 ต่อคำถาม จ่ายให้ provider โดยตรง', 'th', 12);

-- Budget alert tracking column
alter table profiles add column if not exists budget_alert_last_sent_on date;
